import contextlibimport copyimport PIL.Imageimport dataclassesimport itertoolsimport osimport randomimport timefrom copy import deepcopyfrom dataclasses import dataclassimport numpy as npimport transformersfrom diffusers import DPMSolverMultistepScheduler, LCMScheduler, EMAModel, is_transformers_availablefrom diffusers.utils import deprecatefrom einops import repeat, rearrangefrom functools import partialfrom peft import LoraConfig# from pytorch_fid.fid_score import calculate_fid_given_pathsfrom torchvision.transforms import Normalize, ToTensor, Composefrom torchvision.transforms.functional import pil_to_tensorfrom typing import Any, Optional, Union, Dict, Literal, Iterableimport mathimport torchimport torch.nn.functional as Ffrom torch.utils.data import Dataset, DataLoaderfrom torch.utils.data._utils.collate import default_collate_fn_map, collatefrom transformers.utils.constants import OPENAI_CLIP_MEAN, OPENAI_CLIP_STD, IMAGENET_DEFAULT_STD, IMAGENET_DEFAULT_MEANfrom unhcv.common import visual_mask, write_im, CfgNode, remove_dir, visual_bbox, get_related_path, replace_suffixfrom unhcv.common.image import visual_tensor, concat_differ_size, visual_feature, putText, masks2mask, gray2color, \    resize_coordinatefrom unhcv.common.types import default_factory, DataDictfrom unhcv.common.utils import find_path, walk_all_files_with_suffix, round_sigfig, dict2strs, add_prefix_to_keys, \    obj_dump, get_base_namefrom unhcv.common.utils.timer import TimerDictfrom unhcv.core.train import TrainConfig, AccelerateTrainerfrom unhcv.datasets.common_datasets import custom_collate_tensor_fn, ConcatDataset, DatasetWithPreprocess, \    sharder_worker_init_fn, ShardWrapperfrom unhcv.nn.functional import grad_layer_wrt_loss, grad_in_mask, grad_scale# from unhcv.nn.metrics import MARSMetric, PairMetric# from unhcv.nn.metrics.remove import ReMoveMetricfrom unhcv.nn.models.diffusion import DiffusionTools, ODEfrom unhcv.nn.utils import monitor_memory, load_checkpoint, PreNorm, freeze_model, get_model_dtype, \    analyse_model_param# from unhcv.projects.diffusion.inpainting.dataset import InpaintingDatasetWithMaskfrom unhcv.projects.rlhf.inpainting_dataset import InpaintingDatasetWithMaskfrom unhcv.projects.rlhf import ErasureDataset, ErasureModel, ErasureModelConfig# from unhcv.third_party.deepfake.c2p import C2P_CLIPfrom unhcv.third_party.distill import FlashDistill, Discriminator, FlashDistillConfig# from unhcv.third_party.mars import MARSPredictor, MARSEntityPredictor# from unhcv.third_party.mars.mars_predictor import MaskFormerSiameseOutputfrom unhcv.third_party.remove import RemoveLoss, RemoveLossOutput, MARSLoss, MARSLossOutput, RemoveLossConfig, \    MARSLossConfig@dataclass(repr=False)class DefaultDatasetConfig(CfgNode):    passcollate_fn_map = default_collate_fn_map.copy(); collate_fn_map[torch.Tensor] = custom_collate_tensor_fncollate_fn_map[PIL.Image.Image] = lambda x, collate_fn_map: xcustom_collate = partial(collate, collate_fn_map=collate_fn_map)@dataclass(repr=False)class RLHFTrainerConfig(TrainConfig):    dataset_collate_fn: type = None    default_dataset_kwargs: Optional[DefaultDatasetConfig] = default_factory(DefaultDatasetConfig())    default_demo_dataset_kwargs: Optional[Dict] = None    dataset_class: Union[type, str] = "InpaintingDatasetWithMask"    max_visual_num_in_training: int = 5    demo_dataset_class: Optional[type] = None    demo_batch_size = 1@dataclasses.dataclassclass RLHFConfig(CfgNode):    sft_on: bool = False    distill_on: bool = False    c2p_on: bool = False    remove_loss_on: bool = False    use_remove_loss_on_distill: bool = True    use_mars_loss_on_distill: bool = False    use_distill_on_non_pair: bool = False    use_mars_on_distill_pair: bool = False    mars_loss_on: bool = False    mars_loss_scale: float = None    mars_loss_scale_on_pair: float = None    denoise_lora_rank: int = 0    student_pretrained_model: str = None    remove_loss_rescale_on: bool = False    remove_loss_rescale_off_on_pair: bool = False    grad_rescale_on: bool = True    grad_rescale_value: float = 2.    grad_rescale_value_for_mars_prob: float = None    use_remove_grad_rescale: bool = False    use_mars_predictor: bool = False    entity_score_thres: float = 0.2    only_train_mars_predictor: bool = False    grad_in_mask: bool = False    def __post_init__(self):        self.student_pretrained_model = find_path(self.student_pretrained_model)@dataclass(repr=False)class RLHFModelConfig(CfgNode):    rlhf_config: RLHFConfig = default_factory(RLHFConfig)    flash_distill_config: FlashDistillConfig = default_factory(FlashDistillConfig)    remove_loss_config: RemoveLossConfig = default_factory(RemoveLossConfig)    erasure_model_config: ErasureModelConfig = default_factory(ErasureModelConfig)    mars_loss_config: MARSLossConfig = default_factory(MARSLossConfig)    def __post_init__(self):        self.flash_distill_config.use_mars_predictor = self.rlhf_config.use_mars_predictor        self.mars_loss_config.entity_del_sundries = self.remove_loss_config.entity_del_sundriesclass MultiDataLoader:    def __init__(self, dataloaders, sample_prob, tags):        self.dataloaders = dataloaders        self.sample_prob = sample_prob        self.index = tuple(range(len(dataloaders)))        self.tags = tags        self.dataset = self.dataloaders[0].dataset        next(iter(self.dataset))        self.dataloader_iters = [iter(var) for var in dataloaders]    def __iter__(self):        while True:            index = np.random.choice(self.index, p=self.sample_prob)            try:                data = next(self.dataloader_iters[index])            except StopIteration:                self.dataloader_iters[index] = iter(self.dataloaders[index])                data = next(self.dataloader_iters[index])            data['tag'] = self.tags[index]            yield dataclass RLHFTrainer(AccelerateTrainer):    config: RLHFTrainerConfig    flash_distill: FlashDistill    def __init__(self, config: RLHFTrainerConfig = RLHFTrainerConfig()):        super().__init__(config)    def init_train_dataset(self, mode="train"):        dataset_config = self.parse_dataset_config()        dataloader = self._init_train_dataset(mode=mode, dataset_config=dataset_config)        if 'train_dataset_kwargs1' in dataset_config:            dataset_config = self.parse_dataset_config()            dataset_config['train_dataset_kwargs'] = dataset_config['train_dataset_kwargs1']            dataloader1 = self._init_train_dataset(mode=mode, dataset_config=dataset_config, dataset_class=ErasureDataset)            if mode == 'train':                dataloader = MultiDataLoader((dataloader, dataloader1), sample_prob=dataset_config['sample_prob'], tags=('pair_label', 'non_pair_label'))            else:                dataloader = (dataloader, dataloader1)        if mode == 'train':            self.train_dataloader = dataloader        return dataloader    def _init_train_dataset(self, dataset_config=None, mode="train", dataset_class=InpaintingDatasetWithMask):        args = self.args        world_size = int(os.environ.get("WORLD_SIZE", "1"))        train_dataset_kwargs = dataset_config.get("train_dataset_kwargs", {})        data_root = dataset_config.pop("data_root", ["dataset/open-images-dataset/train/lmdb",                                                     "dataset/open-images-dataset/train/lmdb_1025"])        use_concat_dataset = dataset_config.pop("use_concat_dataset", True)        data_indexes_root = find_path(            dataset_config.pop("data_indexes_root", "dataset/open-images-dataset/train/lmdb_1025"))        data_indexes_suffix = dataset_config.pop("data_indexes_suffix", "_catalog.bson")        data_indexes_paths = walk_all_files_with_suffix(data_indexes_root, suffixs=(data_indexes_suffix,), sort=True)        # dataset_class = ErasureDataset        parallel_read_num = 1        parallel_read_num = math.ceil(parallel_read_num / args.train_batch_size) * args.train_batch_size        common_config = dict(batch_size=parallel_read_num, parallel_read_num=parallel_read_num) # , shuffle=True        common_config.update(train_dataset_kwargs)        custom_config = []        for data_indexes_path in data_indexes_paths:            data_path = data_indexes_path[:-len(data_indexes_suffix)]            if isinstance(data_root, str):                data_path = data_path.replace(data_indexes_root, data_root)            else:                data_path = [data_path.replace(data_indexes_root, var) for var in data_root]            file_informs = os.path.basename(data_indexes_path).replace("-", "_").split("_")            length = int([var for var in file_informs if 'num' in var][0].replace('num', ''))            custom_config.append(dict(data_indexes_path=data_indexes_path, data_root=data_path, length=length))        if mode == 'train':            if use_concat_dataset:                dataset = ConcatDataset(dataset_class, common_config=common_config, custom_configs=custom_config)            else:                data_path = dataset_config.pop("data_path", None)                custom_config[0].pop("length", 0)                dataset = dataset_class(**common_config, **custom_config[0])                dataset = ShardWrapper(dataset, random_shuffle=True, drop_last=False, infinite=True)            train_dataloader = DataLoader(                dataset=dataset,                batch_size=args.train_batch_size,                num_workers=args.dataloader_num_workers,                prefetch_factor=8 if args.dataloader_num_workers > 0 else None,                collate_fn=torch.utils.data.default_collate,                pin_memory=True,                worker_init_fn=partial(sharder_worker_init_fn, seed=args.seed))            self.train_dataloader = train_dataloader            return train_dataloader        else:            common_config.update(dict(batch_size=1, parallel_read_num=1, shuffle=False))            i_data_for_test = 40            custom_config[i_data_for_test].pop("length", 0)            # common_config['transforms_kwargs']['transform_method'] = "center_crop"            dataset = dataset_class(**common_config, **custom_config[i_data_for_test])            dataset = ShardWrapper(dataset, random_shuffle=False, drop_last=False, infinite=False, max_num=100, fix_seed_for_all=True)            dataloader = DataLoader(                dataset=dataset,                batch_size=1,                num_workers=2, # args.dataloader_num_workers,                prefetch_factor=8 if args.dataloader_num_workers > 0 else None,                collate_fn=torch.utils.data.default_collate,                pin_memory=True,                worker_init_fn=sharder_worker_init_fn,                drop_last=True)            return dataloader    def init_model(self):        super().init_model()        model_config = self.parse_model_config()        self.rlhf_model_config = RLHFModelConfig.from_other(model_config)        self.rlhf_config = self.rlhf_model_config.rlhf_config        erasure_model_config = self.rlhf_model_config.erasure_model_config        erasure_model_config.train_dtype = self.weight_dtype        self.erasure_model: ErasureModel = ErasureModel(erasure_model_config)        self.erasure_model_config: ErasureModelConfig = self.erasure_model.config        self.denoiser = self.erasure_model.denoiser        self.vae = self.erasure_model.vae        teacher_denoiser = deepcopy(self.denoiser)        freeze_model(teacher_denoiser)        if self.rlhf_config.student_pretrained_model is not None:            load_checkpoint(self.denoiser, self.rlhf_config.student_pretrained_model)        if self.rlhf_config.denoise_lora_rank != 0:            student_unet_lora_config = LoraConfig(                r=self.rlhf_config.denoise_lora_rank,                lora_alpha=self.rlhf_config.denoise_lora_rank,                init_lora_weights="gaussian",                target_modules=["to_k", "to_q", "to_v", "to_out.0"])            self.denoiser.add_adapter(student_unet_lora_config)        self.text_feature = self.erasure_model.text_feature        self.ddpm_scheduler = DiffusionTools.build_scheduler(self.erasure_model_config.denoise_pretrained_root)        self.ddpm_scheduler.alphas_cumprod = self.ddpm_scheduler.alphas_cumprod.cuda()        if self.rlhf_config.sft_on:            self.ddim_scheduler = DiffusionTools.build_scheduler(self.erasure_model_config.denoise_pretrained_root, name="DDIM")            self.dpm_scheduler = DiffusionTools.build_scheduler(self.erasure_model_config.denoise_pretrained_root, scheduler=DPMSolverMultistepScheduler, timestep_spacing="trailing")        self.model = (self.denoiser, )        collector = {}        if self.rlhf_config.use_mars_predictor:            self.mars_predictor = MARSEntityPredictor(self.denoiser, collector=collector)            self.model += (self.mars_predictor,)        if self.rlhf_config.distill_on:            class ErasureDenoiser:                @staticmethod                def forward(self, sample, *args, return_up_features=False, **kwargs):                    masked_latent = self.collector["masked_latent"]                    inpainting_mask = self.collector["inpainting_mask"]                    # return_up_features = kwargs.get("return_up_features", False)                    sample = torch.cat((sample, inpainting_mask, masked_latent), dim=1).to(sample)                    if return_up_features:                        return self._forward(sample, *args, **kwargs)                    else:                        return self._forward(sample, *args, **kwargs).sample            self.collector = collector            sd_path = self.erasure_model_config.denoise_pretrained_root            teacher_scheduler = DPMSolverMultistepScheduler.from_pretrained(                sd_path,                subfolder="scheduler",                timestep_spacing="trailing",            )            sampling_scheduler = LCMScheduler.from_pretrained(                sd_path,                subfolder="scheduler",                timestep_spacing="trailing",            )            teacher_sampling_scheduler = DPMSolverMultistepScheduler.from_pretrained(                sd_path,                subfolder="scheduler",            )            discriminator = Discriminator()            flash_distill_config = self.rlhf_model_config.flash_distill_config            flash_distill_config.train_dtype = self.weight_dtype            flash_distill_config.return_rgb_output = self.rlhf_config.c2p_on            self.flash_distill = FlashDistill(                flash_distill_config,                student_denoiser=self.denoiser,                teacher_denoiser=teacher_denoiser,                teacher_noise_scheduler=teacher_scheduler,                sampling_noise_scheduler=sampling_scheduler,                teacher_sampling_noise_scheduler=teacher_sampling_scheduler,                discriminator=discriminator,                collector=collector,                vae=self.vae,                custom_forward=ErasureDenoiser.forward            ).cuda()            discriminator = self.flash_distill.discriminator            self.flash_distill_config = self.flash_distill.config            self.model = self.model[:1] + (discriminator, ) + self.model[1:]            self.sampling_scheduler = sampling_scheduler            self.ddim_scheduler = DiffusionTools.build_scheduler(self.erasure_model_config.denoise_pretrained_root,                                                                 name="DDIM", timestep_spacing="trailing")            self.ddpm_scheduler = DiffusionTools.build_scheduler(self.erasure_model_config.denoise_pretrained_root)            self.lcm_sccheduler = DiffusionTools.build_scheduler(self.erasure_model_config.denoise_pretrained_root,                                                                 name="CustomLCM", timestep_spacing="trailing")            self.flash_distill.custom_lcm_scheduler = self.lcm_sccheduler            self.ddpm_scheduler.alphas_cumprod = self.ddpm_scheduler.alphas_cumprod.cuda()        if self.rlhf_config.c2p_on:            self.deepfake_model = C2P_CLIP(name=find_path('model/clip-vit-large-patch14'), num_classes=1)            load_checkpoint(self.deepfake_model, find_path('model/C2P_CLIP/C2P_CLIP_release_20240901.pth'), log_missing_keys=True)            self.deepfake_model = self.deepfake_model.to(self.weight_dtype).cuda()            self.deepfake_model = self.deepfake_model.eval(); freeze_model(self.deepfake_model)            self.pre_norm_clip = PreNorm(pixel_mean=OPENAI_CLIP_MEAN, pixel_std=OPENAI_CLIP_STD).to(self.weight_dtype).cuda()        if self.rlhf_config.remove_loss_on:            remove_loss_config = self.rlhf_model_config.remove_loss_config            self.remove_loss = RemoveLoss(remove_loss_config)            self.remove_loss = self.remove_loss.to('cuda', dtype=self.weight_dtype)            if remove_loss_config.use_gan:                self.model += (self.remove_loss.gan_transformers, )                self.remove_loss_training_G = True        if self.rlhf_config.mars_loss_on or self.rlhf_config.use_mars_predictor \                or self.rlhf_model_config.remove_loss_config.use_teacher_entity_on_pair_data:            mars_loss_config = self.rlhf_model_config.mars_loss_config            self.mars_loss = MARSLoss(mars_loss_config)            self.mars_loss = self.mars_loss.to('cuda', dtype=self.weight_dtype)            if hasattr(self, "flash_distill"):                self.flash_distill.mars_loss = self.mars_loss        if self.rlhf_config.only_train_mars_predictor:            self.model = (self.mars_predictor, )            self.denoiser = self.denoiser.to(self.weight_dtype)            freeze_model(self.denoiser)    def init_ema(self):        if self.args.use_ema:            ema_model = tuple([EMAModel(deepcopy(list(var.parameters())), update_after_step=self.args.ema_update_after_step) for var in self.model[:1]])            _ = [var.to(self.accelerator.device) for var in ema_model]            self.ema_model = ema_model    def init_for_train(self):        super().init_for_train()        self.feed_models()    def feed_models(self):        if self.rlhf_config.only_train_mars_predictor:            pass        else:            self.erasure_model.feed_models(self.model[0])            self.denoiser = self.model[0]            if hasattr(self, "flash_distill"):                self.flash_distill.feed_models(self.model[:2])            if self.rlhf_model_config.remove_loss_config.use_gan:                self.remove_loss.feed_models(self.model[2])    def prepare_common_input(self, batch):        image = batch['image'].to(device='cuda', dtype=self.weight_dtype) * 2 - 1        image_gt = image.clone()        inpainting_mask = batch['inpainting_mask'].to(device='cuda', dtype=self.weight_dtype)[:, None]        inpainting_mask_bool = (inpainting_mask > 0)        image[inpainting_mask_bool.repeat(1, 3, 1, 1)] = self.erasure_model_config.inpaint_pad_value        if 'mask' in batch:            entity_mask = batch['mask'].to(device='cuda', dtype=self.weight_dtype)[:, None]        else:            entity_mask = None        return image, image_gt, inpainting_mask, entity_mask    def prepare_image_latent_and_mask(self, image, image_gt, inpainting_mask):        input_image_latent = self.vae.encode(image).float()        gt_image_latent = self.vae.encode(image_gt).float()        inpainting_mask_latent = F.interpolate(inpainting_mask, input_image_latent.shape[-2:]).float()        return input_image_latent, gt_image_latent, inpainting_mask_latent    def distill_loss(self, input_image_latent, gt_image_latent, inpainting_mask_latent, *, inpainting_mask, i_optim, use_gt, use_mars, data_tag):        conditioning = dict(encoder_hidden_states=self.text_feature.repeat(input_image_latent.size(0), 1, 1))        self.collector["inpainting_mask"] = inpainting_mask_latent        self.collector["masked_latent"] = input_image_latent        self.collector["inpainting_mask_ori"] = inpainting_mask        distill_output = self.flash_distill.forward(gt_image_latent, conditioning=conditioning, unconditional_conditioning=None, step=i_optim, use_gt=use_gt, use_mars=use_mars, data_tag=data_tag)        return distill_output    def get_loss(self, batch: Any, i_optim=None):        training_G = self.global_step % 2 == 0        training_G = i_optim == 0        model = self.model[0]        image, image_gt, inpainting_mask, entity_mask = self.prepare_common_input(batch)        input_image_latent, gt_image_latent, inpainting_mask_latent = self.prepare_image_latent_and_mask(image, image_gt, inpainting_mask)        mars_output_teacher = decoded_student_scale1 = decoded_student = mars_predictor_output = mars_loss_output = remove_loss_dict = distill_output = None        tag: Literal["non_pair_label", "pair_label"] = batch.get("tag", "pair_label")        loss_dict = {}        if self.rlhf_config.distill_on:            if tag == "pair_label" or self.rlhf_config.use_distill_on_non_pair:                use_gt = True                use_mars = False                if tag == "non_pair_label" or self.rlhf_config.use_mars_on_distill_pair:                    use_gt = False                    use_mars = True                distill_output = self.distill_loss(input_image_latent, gt_image_latent, inpainting_mask_latent, i_optim=i_optim, use_gt=use_gt, inpainting_mask=inpainting_mask, use_mars=use_mars, data_tag=tag)                loss_dict.update(distill_output["loss"])                decoded_student = distill_output['lpips_output']['decoded_student']                mars_output_teacher = distill_output['lpips_output'].get("mars_output", None)            else:                noise = DiffusionTools.generate_noise(input_image_latent)                encoder_hidden_states = self.text_feature.repeat(noise.size(0), 1, 1)                self.collector["masked_latent"] = input_image_latent                self.collector["inpainting_mask"] = inpainting_mask_latent                decoded_student = ODE.ode(self.lcm_sccheduler, self.denoiser, noise, condition=dict(encoder_hidden_states=encoder_hidden_states), generator=None, guidance_scale=1, steps=1, requires_grad=True)                decoded_student = self.vae.decode(decoded_student.to(self.weight_dtype))            if self.rlhf_config.c2p_on:                decoded_student_to_clip = (F.interpolate(decoded_student, (224, 224), mode='bicubic')).clamp(-1., 1.0)                decoded_student_to_clip = decoded_student_to_clip * 0.5 + 0.5                decoded_student_to_clip = self.pre_norm_clip(decoded_student_to_clip)                fake_score = self.deepfake_model(decoded_student_to_clip).float().sigmoid()                loss_dict['deepfake_loss'] = (fake_score**2).mean()            if self.rlhf_config.mars_loss_on:                if (tag == "pair_label" and self.rlhf_config.use_mars_loss_on_distill) or \                        tag == "non_pair_label":                    if decoded_student_scale1 is None:                        decoded_student_scale1 = decoded_student * 0.5 + 0.5                    if self.rlhf_config.grad_in_mask:                        decoded_student_scale1 = grad_in_mask(decoded_student_scale1, inpainting_mask)                    mars_loss_output = self.mars_loss.forward(decoded_student_scale1, inpainting_mask, entity_mask)                    loss = {}                    def mars_scale_loss(loss, scale, key):                        if isinstance(scale, dict):                            if key in scale:                                return grad_scale(loss, scale[key])                            else:                                return loss                        else:                            return grad_scale(loss, scale)                    for key, value in mars_loss_output['loss'].items():                        loss_ = value.mean()                        if self.rlhf_config.mars_loss_scale_on_pair is not None and tag == "pair_label":                            loss_ = mars_scale_loss(loss_, self.rlhf_config.mars_loss_scale_on_pair, key)                        elif self.rlhf_config.mars_loss_scale is not None:                            loss_ = mars_scale_loss(loss_, self.rlhf_config.mars_loss_scale, key)                        loss[key] = loss_                    loss_dict.update(loss)            if self.rlhf_config.remove_loss_on:                if (tag == "pair_label" and self.rlhf_config.use_remove_loss_on_distill) or \                        tag == "non_pair_label":                    if decoded_student_scale1 is None:                        decoded_student_scale1 = decoded_student * 0.5 + 0.5                    if mars_loss_output is not None:                        pred_masks_filter_sundries = mars_loss_output.pred_masks_filter_sundries                    else:                        pred_masks_filter_sundries = None                    if self.rlhf_model_config.remove_loss_config.use_gan:                        if self.remove_loss_training_G:                            inpainting_mask_real_fake = inpainting_mask                            real_fake = decoded_student_scale1                            labels = real_fake.new_ones([real_fake.size(0)], dtype=torch.float)                        else:                            real = self.vae.decode(gt_image_latent.to(self.weight_dtype)) * 0.5 + 0.5                            inpainting_mask_real_fake = inpainting_mask.repeat(2, 1, 1, 1)                            fake = decoded_student_scale1.detach()                            real_fake = torch.cat((real, fake), dim=0)                            labels = real.new_zeros([real.size(0) * 2], dtype=torch.float)                            labels[:real.size(0)] = 1                        remove_loss_dict = self.remove_loss.forward(real_fake, inpainting_mask_real_fake, None, labels=labels, mars_loss_output=mars_loss_output)                        remove_loss_dict['loss'] = add_prefix_to_keys(remove_loss_dict['loss'], f'trainG{int(self.remove_loss_training_G)}_')                        if not self.remove_loss_training_G:                            remove_loss_dict['predict_image_rect_grad'] = remove_loss_dict['predict_image_rect_grad'].detach()                    else:                        if mars_output_teacher is None and self.remove_loss.config.use_teacher_entity_on_pair_data:                            mars_output_teacher = self.mars_loss.predict_mars_masks(distill_output['lpips_output']['decoded_teacher'], self.collector['inpainting_mask_ori'], ios_thres=0.85)                        if mars_loss_output is None:                            mars_loss_output = self.mars_loss.forward(decoded_student_scale1, inpainting_mask, entity_mask)                            pred_masks_filter_sundries = mars_loss_output.pred_masks_filter_sundries                        remove_loss_dict = self.remove_loss.forward(decoded_student_scale1, inpainting_mask, entity_mask, pred_masks_filter_sundries=pred_masks_filter_sundries, mars_loss_output=mars_loss_output, mars_output_teacher=mars_output_teacher, data_tag=tag)                    loss = {}                    for key, value in remove_loss_dict['loss'].items():                        loss[key] = value.mean()                    loss_dict.update(loss)                    if remove_loss_dict.predict_image_rect_grad is not None:                        loss_dict[key] += remove_loss_dict.predict_image_rect_grad            else:                if mars_loss_output is not None:                    loss_dict["remove_loss"] = mars_loss_output.mask_features.mean() * 0            if self.rlhf_config.use_mars_predictor:                if 0 and training_G:                    pass                else:                    if decoded_student is None:                        noisy_latents = DiffusionTools.generate_noise(gt_image_latent)                        encoder_hidden_states = self.text_feature.repeat(noisy_latents.size(0), 1, 1)                        timesteps = 999                        student_output_feature = self.erasure_model.denoise(noisy_latents.to(self.weight_dtype), timesteps, encoder_hidden_states, inpainting_mask_latent, input_image_latent)                        predict = DiffusionTools.delete_noise(self.ddpm_scheduler, noisy_latents, student_output_feature.sample, timesteps)                        decoded_student = self.vae.decode(predict.to(self.weight_dtype))                    else:                        student_output_feature = distill_output["student_output_feature"]                    input_shape = image.shape[2:]                    if mars_loss_output is None:                        with torch.no_grad():                            if decoded_student_scale1 is None:                                decoded_student_scale1 = decoded_student * 0.5 + 0.5                            mars_loss_output = self.mars_loss.forward(decoded_student_scale1, inpainting_mask, entity_mask)                    pred_masks = F.interpolate(mars_loss_output.pred_masks, input_shape, mode='bilinear')                    targets = []                    with torch.no_grad():                        for i_image, (pred_mask, pred_prob) in enumerate(zip(pred_masks, mars_loss_output.pred_probs)):                            valid = pred_prob > self.rlhf_config.entity_score_thres                            pred_mask = pred_mask[valid]                            pred_prob = pred_prob[valid]                            gt_classes = torch.zeros_like(pred_prob, dtype=torch.long)                            pred_mask = pred_mask > 0                            if mars_loss_output.pred_mars_masks is None:                                mars_mask = pred_mask.new_zeros([1, *input_shape], dtype=torch.bool)                            else:                                mars_mask = mars_loss_output.pred_mars_masks[mars_loss_output.sundries_b_indices == i_image]                                if mars_mask.size(0) > 0:                                    mars_mask = F.interpolate(mars_mask[None], input_shape, mode='bilinear')[0].max(0)[0][None] > 0                                else:                                    mars_mask = mars_mask.new_zeros([1, *input_shape], dtype=torch.bool)                            masks = torch.cat([pred_mask, mars_mask], dim=0)                            # masks = pred_mask                            # masks_show = visual_tensor(masks[:, None].float(), max_value=1, min_value=0, square_flatten=True)                            gt_classes = torch.cat([gt_classes, gt_classes.new_tensor([1])])                            targets.append(dict(labels=gt_classes, masks=masks))                    mars_predictor_output: MaskFormerSiameseOutput = self.mars_predictor(student_output_feature, targets=targets, training_G=training_G)                    mars_predictor_output.set(targets=targets, student_output_feature=student_output_feature, decoded_student=decoded_student)                    # visual_tensor(k[0, :, None], max_value=1, min_value=0, square_flatten=True)                    loss_dict.update(mars_predictor_output.losses)            timesteps = noisy_latents = predict = encoder_hidden_states = None            if 0 and self.denoiser.conv_out.weight.requires_grad == True:                rescale = 2                loss_G_scale = grad_layer_wrt_loss(loss_dict['loss_G'], self.denoiser.conv_out.weight).norm(p=2)                print('loss_G scale: {}'.format(loss_G_scale))                loss_G_scale = loss_G_scale / rescale                if 'trainG1_gan_loss' in loss_dict and loss_dict['trainG1_gan_loss'] is not None and loss_dict['trainG1_gan_loss'].requires_grad == True:                    trainG1_gan_loss = grad_layer_wrt_loss(loss_dict['trainG1_gan_loss'], self.denoiser.conv_out.weight).norm(p=2)                    print('trainG1_gan_loss scale: {}'.format(trainG1_gan_loss))                    if trainG1_gan_loss > loss_G_scale:                        adaptive_weight = loss_G_scale / trainG1_gan_loss                        loss_dict['trainG1_gan_loss'] = loss_dict['trainG1_gan_loss'] * adaptive_weight            loss_G_scale = None            if self.rlhf_config.use_remove_grad_rescale:                breakpoint()                remove_loss = loss_dict.get('remove_loss_entity', None)                remove_loss_global = loss_dict.get('remove_loss_global', None)                if remove_loss_global is not None:                    if remove_loss is not None:                        remove_loss += remove_loss_global                    else:                        remove_loss = remove_loss_global                if remove_loss is not None:                    loss_G_scale = grad_layer_wrt_loss(loss_dict['loss_distill'], self.denoiser.conv_out.weight).norm(p=2)                    remove_loss_entity_scale = grad_layer_wrt_loss(remove_loss, self.denoiser.conv_out.weight).norm(p=2)                    balance_scale = loss_G_scale / remove_loss_entity_scale                    if 'remove_loss_entity' in loss_dict:                        loss_dict['remove_loss_entity'] *= balance_scale                    if 'remove_loss_global' in loss_dict:                        loss_dict['remove_loss_global'] *= balance_scale                    print('remove_loss_entity_scale scale: {}'.format(remove_loss_entity_scale))                    # grad_layer_wrt_loss(loss_dict['remove_loss_entity'], self.denoiser.conv_out.weight).norm(p=2)            if self.rlhf_config.grad_rescale_on and self.denoiser.conv_out.weight.requires_grad == True:                rescale = self.rlhf_config.grad_rescale_value                if loss_G_scale is None:                    loss_G_scale = grad_layer_wrt_loss(loss_dict['loss_distill'], self.denoiser.conv_out.weight).norm(p=2)                loss_G_scale_ = loss_G_scale                print('loss_G scale: {}'.format(loss_G_scale))                loss_G_scale = loss_G_scale / rescale                if 'mars_mask_loss' in loss_dict and loss_dict['mars_mask_loss'] is not None and loss_dict['mars_mask_loss'].requires_grad == True:                    mars_mask_loss_scale = grad_layer_wrt_loss(loss_dict['mars_mask_loss'], self.denoiser.conv_out.weight).norm(p=2)                    print('mars_mask_loss scale: {}'.format(mars_mask_loss_scale))                    if mars_mask_loss_scale > loss_G_scale:                        adaptive_weight = loss_G_scale / mars_mask_loss_scale                        loss_dict['mars_mask_loss'] = grad_scale(loss_dict['mars_mask_loss'], adaptive_weight)                        # loss_dict['mars_mask_loss'] = loss_dict['mars_mask_loss'] * adaptive_weight                if self.rlhf_config.grad_rescale_value_for_mars_prob is not None:                    if 'mars_prob_loss' in loss_dict and loss_dict['mars_prob_loss'] is not None and loss_dict['mars_prob_loss'].requires_grad == True:                        mars_prob_loss_scale = grad_layer_wrt_loss(loss_dict['mars_prob_loss'], self.denoiser.conv_out.weight).norm(p=2)                        print('mars_prob_loss scale: {}'.format(mars_prob_loss_scale))                        loss_G_scale_prob_for_mars_prob = loss_G_scale_ / self.rlhf_config.grad_rescale_value_for_mars_prob                        if mars_prob_loss_scale > loss_G_scale_prob_for_mars_prob:                            adaptive_weight = loss_G_scale_prob_for_mars_prob / mars_prob_loss_scale                            loss_dict['mars_prob_loss'] = grad_scale(loss_dict['mars_prob_loss'], adaptive_weight)                remove_loss_rescale_on = self.rlhf_config.remove_loss_rescale_on                if tag == "pair_label" and self.rlhf_config.remove_loss_rescale_off_on_pair:                    remove_loss_rescale_on = False                if remove_loss_rescale_on:                    if 'remove_loss_global' in loss_dict:                        remove_loss_global_scale = grad_layer_wrt_loss(loss_dict['remove_loss_global'], self.denoiser.conv_out.weight).norm(p=2)                        print('remove_loss_global scale: {}'.format(remove_loss_global_scale))                        if remove_loss_global_scale > loss_G_scale:                            adaptive_weight = loss_G_scale / remove_loss_global_scale                            loss_dict['remove_loss_global'] = loss_dict['remove_loss_global'] * adaptive_weight                    if 'remove_loss_entity' in loss_dict:                        remove_loss_entity_scale = grad_layer_wrt_loss(loss_dict['remove_loss_entity'], self.denoiser.conv_out.weight).norm(p=2)                        print('remove_loss_entity scale: {}'.format(remove_loss_entity_scale))                        if remove_loss_entity_scale > loss_G_scale:                            adaptive_weight = loss_G_scale / remove_loss_entity_scale                            loss_dict['remove_loss_entity'] = grad_scale(loss_dict['remove_loss_entity'], adaptive_weight)                            remove_loss_entity_scale = grad_layer_wrt_loss(loss_dict['remove_loss_entity'],                                                                           self.denoiser.conv_out.weight).norm(p=2)                            print('after remove_loss_entity scale: {}'.format(remove_loss_entity_scale))        else:            assert self.rlhf_config.sft_on            distill_output = None            noisy_latents, unet_target, timesteps = DiffusionTools.add_noise(self.ddpm_scheduler, gt_image_latent)            encoder_hidden_states = self.text_feature.repeat(noisy_latents.size(0), 1, 1)            predict = self.erasure_model.denoise(noisy_latents, timesteps, encoder_hidden_states, inpainting_mask_latent, input_image_latent)            mse_loss = F.mse_loss(predict.sample.float(), unet_target.float())            loss_dict = {"mse_loss": mse_loss}        return loss_dict    def train_step(self, batch):        if self.rlhf_config.sft_on or self.rlhf_config.only_train_mars_predictor:            return super().train_step(batch)        accelerator = self.accelerator        args = self.args        for i_optim in range(2):            (optimizer, lr_scheduler, optimizer, model) = (self.optimizer[i_optim], self.lr_scheduler[i_optim], self.optimizer[i_optim], self.model[i_optim])            # optimizer.param_groups[0]["params"][0].grad            optimizer.zero_grad(set_to_none=True)            if self.rlhf_model_config.remove_loss_config.use_gan:                raise NotImplementedError                if not self.remove_loss_training_G:                    self.optimizer[2].zero_grad(set_to_none=True)            if self.rlhf_config.use_mars_predictor:                raise NotImplementedError                if 1 or i_optim == 1:                    self.optimizer[2].zero_grad(set_to_none=True)            loss_dict = self.get_loss(batch, i_optim)            # Gather the losses across all processes for logging (if we use distributed training).            loss_for_backward = sum(loss_dict.values())            for key, value in loss_dict.items():                if isinstance(value, torch.Tensor):                    value = accelerator.reduce(value, "mean").item()                loss_dict[key] = value            loss_sum = accelerator.reduce(loss_for_backward, "mean").item()            self.mean_cache.update(dict(loss=loss_sum))            self.mean_cache.update(loss_dict)            # Backward            if self.args.debug:                monitor_memory("before loss_for_backward")            accelerator.backward(loss_for_backward)            if self.args.debug:                monitor_memory("after loss_for_backward")            if args.max_grad_norm != 0 and accelerator.sync_gradients:                grad_before_norm = accelerator.clip_grad_norm_(model.parameters(), args.max_grad_norm)                if grad_before_norm is not None:                    if isinstance(grad_before_norm, torch.Tensor):                        grad_before_norm = grad_before_norm.item()                    self.mean_cache.update({f"grad": grad_before_norm})            if self.args.debug:                monitor_memory("before optimizer")            optimizer.step()            lr_scheduler.step()            if self.args.debug:                monitor_memory("after optimizer")            if self.rlhf_model_config.remove_loss_config.use_gan \                    or self.rlhf_config.use_mars_predictor:                raise NotImplementedError                if 0 and i_optim == 0:                    print('training G')                    pass                else:                    print('training D')                    self.optimizer[2].step()                    self.lr_scheduler[2].step()    def ema_step(self):        if self.args.use_ema:            for ema_model_, model_ in zip(self.ema_model[:1], self.model[:1]):                ema_model_.step(model_.parameters())    def inference_on_test(self, global_step):        pass    def visual_latent(self, latent, name=None, reverse=True):        with torch.no_grad():            image = self.vae.decode(latent.to(self.weight_dtype))            image = visual_tensor(image, max_value=1, min_value=-1, max_num=5, reverse=reverse, name=name)        return image    def visual_tensor(self, image):        image = visual_tensor(image, max_value=1, min_value=-1, max_num=5, reverse=True)        return image    def main(self):        if self.args.eval_only:            self.inference(global_step=0)        else:            if self.args.debug:                self.logger.info("verify save_state")                # self.save_state()                self.logger.info("verify inference")                # self.inference(global_step=0)            self.train()if __name__ == "__main__":    trainer = RLHFTrainer()    trainer.main()    pass